1	<script lang="ts">
2		// DotMeter v2, the judge's hand-built take, for direct iteration with Jake.
3		// The design thesis: multiply-and-add should be VISIBLE, not narrated.
4		// Every bar is literally its two products stacked; the strip below shows
5		// the arithmetic for whichever candidate you select, live, to two decimals.
6	
7		// The two entries mean something: x is how loud, y is how fast.
8		const CANDIDATES = [
9			{ id: 'c1', name: 'Night Drive', angle: 20 },
10			{ id: 'c2', name: 'Glass Rain', angle: 70 },
11			{ id: 'c3', name: 'Slow Burn', angle: 110 },
12			{ id: 'c4', name: 'Static', angle: 160 }
13		];
14	
15		let challenge = $state<null | 'cheat' | 'short'>(null);
16		let solvedCheat = $state(false);
17		let solvedShort = $state(false);
18		const WHY = {
19			cheat:
20				'A song that is simply louder and faster everywhere piles up score without matching your mix. A raw meter overrates intense tracks, so a recommender built on it keeps pushing whatever is biggest.',
21			short:
22				'A quiet song that matches your mix exactly gets buried under bigger ones. Size is drowning direction, and fixing that is exactly where this lesson is headed.'
23		};
24		function startChallenge(kind: 'cheat' | 'short') {
25			// one click always re-arms: a solved card resets on first click,
26			// whether or not another challenge was active in between
27			if (kind === 'cheat' && (challenge === 'cheat' || solvedCheat)) solvedCheat = false;
28			if (kind === 'short' && (challenge === 'short' || solvedShort)) solvedShort = false;
29			challenge = kind;
30			probeAngle = 40;
31			lengthC1 = 1.0;
32			selected = 'c1';
33		}
34		$effect(() => {
35			if (challenge === 'cheat' && cheatActive) solvedCheat = true;
36			if (challenge === 'short' && shortChanged) solvedShort = true;
37		});
38	
39		let probeAngle = $state(40);
40		let lengthC1 = $state(1.0);
41		let selected = $state('c1');
42		let hovered = $state<string | null>(null);
43		let dragging = $state<'probe' | 'length' | null>(null);
44	
45		const rad = (d: number) => (d * Math.PI) / 180;
46	
47		const probe = $derived({ x: Math.cos(rad(probeAngle)), y: Math.sin(rad(probeAngle)) });
48	
49		const rows = $derived(
50			CANDIDATES.map((c) => {
51				const len = c.id === 'c1' ? lengthC1 : 1;
52				const x = len * Math.cos(rad(c.angle));
53				const y = len * Math.sin(rad(c.angle));
54				const px = probe.x * x; // the x-term product
55				const py = probe.y * y; // the y-term product
56				return { ...c, len, x, y, px, py, score: px + py };
57			})
58		);
59	
60		const maxScore = $derived(Math.max(...rows.map((r) => r.score)));
61		const leaders = $derived(rows.filter((r) => Math.abs(r.score - maxScore) < 0.005).map((r) => r.id));
62		const tied = $derived(leaders.length > 1);
63		const sel = $derived(rows.find((r) => r.id === selected) ?? rows[0]);
64	
65		// The mirror lesson: c1 aims truest but is too short to win.
66		const shortChanged = $derived.by(() => {
67			const c1 = rows[0];
68			if (lengthC1 >= 0.95 || leaders.includes('c1')) return false;
69			return rows.every(
70				(r) =>
71					r.id === 'c1' ||
72					Math.abs(((r.angle - probeAngle + 540) % 360) - 180) >
73						Math.abs(((c1.angle - probeAngle + 540) % 360) - 180)
74			);
75		});
76	
77		// The overtake: c1 stretched AND outscoring a candidate that out-aligns it.
78		// Returns the most deserving victim (best-aligned beaten song) so the flag
79		// can name the exact pair instead of making a vague claim about the board.
80		const cheatVictim = $derived.by(() => {
81			const c1 = rows[0];
82			if (lengthC1 <= 1.05) return null;
83			const dist = (angle: number) => Math.abs(((angle - probeAngle + 540) % 360) - 180);
84			const beaten = rows.filter(
85				(r) => r.id !== 'c1' && dist(r.angle) < dist(c1.angle) && c1.score > r.score + 0.005
86			);
87			if (beaten.length === 0) return null;
88			return beaten.reduce((a, b) => (dist(a.angle) < dist(b.angle) ? a : b));
89		});
90		const cheatActive = $derived(cheatVictim !== null);
91		const leaderName = $derived(rows.find((r) => r.id === leaders[0])?.name ?? '');
92	
93		// --- Arena geometry (SVG units) ---
94		const S = 400; // viewBox square
95		const CX = S / 2;
96		const CY = S / 2;
97		const R = 92; // unit arrow length in px; 2.0 x R stays inside the frame
98		const pt = (x: number, y: number) => ({ px: CX + x * R, py: CY - y * R });
99	
100		function arrow(x: number, y: number) {
101			const tip = pt(x, y);
102			const ang = Math.atan2(CY - tip.py, tip.px - CX);
103			const L = Math.hypot(tip.px - CX, tip.py - CY);
104			const head = Math.max(7, Math.min(11, L * 0.09));
105			const back = { px: tip.px - head * Math.cos(ang), py: tip.py + head * Math.sin(ang) };
106			const left = {
107				px: back.px - head * 0.55 * Math.sin(ang),
108				py: back.py - head * 0.55 * Math.cos(ang)
109			};
110			const right = {
111				px: back.px + head * 0.55 * Math.sin(ang),
112				py: back.py + head * 0.55 * Math.cos(ang)
113			};
114			return {
115				shaft: { x1: CX, y1: CY, x2: back.px, y2: back.py },
116				head: `${tip.px},${tip.py} ${left.px},${left.py} ${right.px},${right.py}`
117			};
118		}
119	
120		function labelPos(angle: number, len: number, pad = 20) {
121			const d = len * R + pad;
122			return { px: CX + d * Math.cos(rad(angle)), py: CY - d * Math.sin(rad(angle)) };
123		}
124	
125		let arenaEl = $state<SVGSVGElement | null>(null);
126	
127		function anglesFromEvent(e: PointerEvent) {
128			if (!arenaEl) return null;
129			const r = arenaEl.getBoundingClientRect();
130			const x = ((e.clientX - r.left) / r.width) * S - CX;
131			const y = CY - ((e.clientY - r.top) / r.height) * S;
132			return { angle: ((Math.atan2(y, x) * 180) / Math.PI + 360) % 360, dist: Math.hypot(x, y) / R };
133		}
134	
135		function onArenaPointer(e: PointerEvent) {
136			const a = anglesFromEvent(e);
137			if (!a || !dragging) return;
138			if (dragging === 'probe') probeAngle = Math.round(a.angle / 5) * 5 % 360;
139			else lengthC1 = Math.max(0.5, Math.min(2, Math.round(a.dist * 10) / 10));
140		}
141	
142		function startDrag(kind: 'probe' | 'length', e: PointerEvent) {
143			dragging = kind;
144			(e.currentTarget as Element).setPointerCapture(e.pointerId);
145		}
146	
147		function probeKeys(e: KeyboardEvent) {
148			let h = true;
149			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') probeAngle = (probeAngle + 5) % 360;
150			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') probeAngle = (probeAngle + 355) % 360;
151			else h = false;
152			if (h) e.preventDefault();
153		}
154	
155		function lengthKeys(e: KeyboardEvent) {
156			let h = true;
157			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') lengthC1 = Math.min(2, Math.round((lengthC1 + 0.1) * 10) / 10);
158			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') lengthC1 = Math.max(0.5, Math.round((lengthC1 - 0.1) * 10) / 10);
159			else h = false;
160			if (h) e.preventDefault();
161		}
162	
163		const f = (n: number) => (Object.is(n, -0) ? 0 : n).toFixed(2);
164		const cl = (v: number) => Math.min(Math.max(v, 24), S - 24);
165		const f1 = (n: number) => (Object.is(n, -0) ? 0 : n).toFixed(1);
166	
167		// Bar scale: scores live in [-2, 2] once c1 can stretch.
168		const BARMAX = 2.05;
169		const barH = 96;
170		const segH = (v: number) => (Math.abs(v) / BARMAX) * (barH / 2);
171	
172		const probeTip = $derived(pt(probe.x, probe.y));
173		const c1row = $derived(rows[0]);
174		const c1HandlePos = $derived(pt(c1row.x, c1row.y));
175	</script>
176	
177	<svelte:window onpointerup={() => (dragging = null)} />
178	
179	<div class="lab" data-interactive="dot-alignment">
180		<p class="invite">
181			Every song here is two numbers: how <em class="qw-loud">loud</em>, how <em class="qw-fast">fast</em>. So is your taste. Turn
182			the amber taste arrow and watch each song's match get <em>built</em>: the <span class="qw-loud">loud product</span> plus
183			the <span class="qw-fast">fast product</span>, stacked into one bar. Then grab Night Drive's round handle and change its size.
184		</p>
185		<div class="challenges">
186			<button class="chal" class:active={challenge === 'cheat' && !solvedCheat} class:done={solvedCheat} onclick={() => startChallenge('cheat')}>
187				<span class="chal-t mono">challenge 01</span>
188				<span class="chal-g">Make a worse match win</span>
189				{#if solvedCheat}
190					<span class="chal-s mono">✓ solved · click to retry</span>
191					<span class="chal-why">{WHY.cheat}</span>
192				{:else if challenge === 'cheat'}
193					<span class="chal-s mono live">in play…</span>
194				{/if}
195			</button>
196			<button class="chal" class:active={challenge === 'short' && !solvedShort} class:done={solvedShort} onclick={() => startChallenge('short')}>
197				<span class="chal-t mono">challenge 02</span>
198				<span class="chal-g">Make the truest song lose</span>
199				{#if solvedShort}
200					<span class="chal-s mono">✓ solved · click to retry</span>
201					<span class="chal-why">{WHY.short}</span>
202				{:else if challenge === 'short'}
203					<span class="chal-s mono live">in play…</span>
204				{/if}
205			</button>
206		</div>
207	
208		<div class="stage">
209			<div class="arena-wrap">
210				<svg
211					bind:this={arenaEl}
212					viewBox="0 0 {S} {S}"
213					class="arena"
214					onpointermove={onArenaPointer}
215					role="img"
216					aria-label="An amber probe arrow among four periwinkle candidate arrows; drag the probe tip to turn it, drag c1's tip to stretch it"
217				>
218					<!-- angle ring + ticks -->
219					<circle cx={CX} cy={CY} r={R} class="ring" />
220					{#each Array.from({ length: 12 }, (_, i) => i * 30) as t (t)}
221						<line
222							x1={CX + (R - 4) * Math.cos(rad(t))}
223							y1={CY - (R - 4) * Math.sin(rad(t))}
224							x2={CX + (R + 4) * Math.cos(rad(t))}
225							y2={CY - (R + 4) * Math.sin(rad(t))}
226							class="tick"
227						/>
228					{/each}
229					<!-- axes, whisper-quiet, but named: the two entries ARE qualities -->
230					<line x1={CX - R - 14} y1={CY} x2={CX + R + 14} y2={CY} class="axis" />
231					<line x1={CX} y1={CY - R - 14} x2={CX} y2={CY + R + 14} class="axis" />
232					<text x={CX + R + 18} y={CY - 6} class="axisq q-loud mono">loud</text>
233					<text x={CX - 10} y={CY - R - 8} text-anchor="end" class="axisq q-fast mono">fast</text>
234					<g class="legend">
235						<line x1="16" y1="20" x2="34" y2="20" class="lg probe-stroke" />
236						<text x="40" y="24" class="lgt mono">your taste</text>
237						<line x1="16" y1="38" x2="34" y2="38" class="lg cand-stroke" />
238						<text x="40" y="42" class="lgt mono">songs</text>
239					</g>
240	
241					<!-- coordinates made visible: dashed drops for probe and selected -->
242					{#each [{ x: probe.x, y: probe.y, cls: 'p' }, { x: sel.x, y: sel.y, cls: 'c' }] as d (d.cls)}
243						{@const tip = pt(d.x, d.y)}
244						<line x1={tip.px} y1={tip.py} x2={tip.px} y2={CY} class="drop {d.cls}" />
245						<line x1={tip.px} y1={tip.py} x2={CX} y2={tip.py} class="drop {d.cls}" />
246						<text x={cl(tip.px)} y={CY + (d.cls === 'p' ? 13 : 25)} class="coord mono {d.cls}">{f(d.x)}</text>
247						<text x={CX - (d.cls === 'p' ? 4 : 32)} y={cl(tip.py) - 3} class="coord mono {d.cls}" text-anchor="end">{f(d.y)}</text>
248					{/each}
249	
250					<!-- candidates -->
251					{#each rows as r (r.id)}
252						{@const a = arrow(r.x, r.y)}
253						<g
254							class="cand"
255							class:sel={selected === r.id}
256							class:hov={hovered === r.id}
257							onpointerdown={() => (selected = r.id)}
258							role="button"
259							tabindex="-1"
260							aria-label={`select ${r.name}`}
261						>
262							<line {...{ x1: a.shaft.x1, y1: a.shaft.y1, x2: a.shaft.x2, y2: a.shaft.y2 }} class="shaft cand-stroke" />
263							<polygon points={a.head} class="cand-fill" />
264							{#if selected === r.id}
265								{@const lp = labelPos(r.angle, r.len, 26)}
266								<text
267									x={Math.min(Math.max(lp.px, 44), S - 48)}
268									y={Math.min(Math.max(lp.py, 16), S - 10)}
269									class="lab song-lab halo">{r.name}</text>
270							{/if}
271						</g>
272					{/each}
273	
274					<!-- probe on top -->
275					{#if true}
276						{@const a = arrow(probe.x, probe.y)}
277						<line {...{ x1: a.shaft.x1, y1: a.shaft.y1, x2: a.shaft.x2, y2: a.shaft.y2 }} class="shaft probe-stroke" />
278						<polygon points={a.head} class="probe-fill" />
279					{/if}
280					<circle
281						cx={probeTip.px}
282						cy={probeTip.py}
283						r="22"
284						onpointermove={onArenaPointer}
285						class="handle probe-handle"
286						class:active={dragging === 'probe'}
287						onpointerdown={(e) => startDrag('probe', e)}
288						onkeydown={probeKeys}
289						role="slider"
290						tabindex="0"
291						aria-label="probe angle in degrees"
292						aria-valuemin="0"
293						aria-valuemax="360"
294						aria-valuenow={Math.round(probeAngle)}
295					/>
296					<!-- Night Drive's length handle. AFTER the probe handle on purpose:
297					     the primary angle slider must be the FIRST [role="slider"] in
298					     the DOM (the drive contract grabs the first one). -->
299					<circle
300						cx={c1HandlePos.px}
301						cy={c1HandlePos.py}
302						r="22"
303						onpointermove={onArenaPointer}
304						class="handle length-handle"
305						class:active={dragging === 'length'}
306						class:pulse={challenge !== null && !((challenge === 'cheat' && cheatActive) || (challenge === 'short' && shortChanged))}
307						onpointerdown={(e) => startDrag('length', e)}
308						onkeydown={lengthKeys}
309						role="slider"
310						tabindex="0"
311						data-control="length-c1"
312						aria-label="c1 length"
313						aria-valuemin="0.5"
314						aria-valuemax="2"
315						aria-valuenow={f1(lengthC1)}
316					/>
317					<text x="14" y={S - 14} class="angle mono">taste at {Math.round(probeAngle)}°</text>
318				</svg>
319			</div>
320	
321			<div class="meter">
322				{#each rows as r (r.id)}
323					<button
324						class="row"
325						class:leading={leaders.includes(r.id) && !tied}
326						class:sel={selected === r.id}
327						onmouseenter={() => (hovered = r.id)}
328						onmouseleave={() => (hovered = null)}
329						onclick={() => (selected = r.id)}
330						aria-label={`${r.name} score ${f(r.score)}${leaders.includes(r.id) && !tied ? ', leading' : ''}`}
331					>
332						<span class="row-id">{r.name}</span>
333						<span class="bar" style="--h: {barH}px">
334							<span class="zero"></span>
335							<!-- x-term segment then y-term segment, stacked from the baseline -->
336							<span
337								class="seg segx"
338								class:neg={r.px < 0}
339								style="height: {segH(r.px)}px; bottom: {r.px >= 0 ? barH / 2 : barH / 2 - segH(r.px)}px"
340							></span>
341							<span
342								class="seg segy"
343								class:neg={r.py < 0}
344								style="height: {segH(r.py)}px; bottom: {r.py >= 0
345									? barH / 2 + (r.px > 0 ? segH(r.px) : 0)
346									: barH / 2 - segH(r.py) - (r.px < 0 ? segH(r.px) : 0)}px"
347							></span>
348						</span>
349						<span class="row-score mono" class:neg={r.score < 0}>{f(r.score)}</span>
350						{#if leaders.includes(r.id) && !tied}<span class="leads mono">leads</span>{/if}
351					</button>
352				{/each}
353				{#if tied}<span class="tie mono">tied</span>{/if}
354				{#if cheatVictim}
355					<span class="flag mono">⚑ {cheatVictim.name} matches your taste better, but Night Drive outscores it on size</span>
356				{:else if shortChanged}
357					<span class="flag short mono">⚑ Night Drive matches best, but {leaderName} wins on size</span>
358				{/if}
359			</div>
360		</div>
361		{#if challenge === null && cheatActive}
362			<p class="why">Why this matters: {WHY.cheat}</p>
363		{:else if challenge === null && shortChanged}
364			<p class="why">Why this matters: {WHY.short}</p>
365		{/if}
366		<p class="hint">
367			Click any bar or arrow to inspect it. The dashed lines are that arrow's two
368			entries (its loudness and its speed), the numbers the recipe multiplies.
369		</p>
370	
371		<div class="strip" aria-live="polite">
372			<span class="strip-lead">the whole recipe, live for <b>{sel.name}</b>:</span>
373			<span class="mono eq">
374				<span class="op qw-loud">loud</span>
375				<span class="probe-c">{f(probe.x)}</span>·<span class="cand-c">{f(sel.x)}</span>
376				<span class="op">+</span>
377				<span class="op qw-fast">fast</span>
378				<span class="probe-c">{f(probe.y)}</span>·<span class="cand-c">{f(sel.y)}</span>
379				<span class="op">=</span>
380				<span class="segx-c">{f(sel.px)}</span>
381				<span class="op">+</span>
382				<span class="segy-c">{f(sel.py)}</span>
383				<span class="op">=</span>
384				<span class="score-c">{f(sel.score)}</span>
385			</span>
386			<span class="strip-note">
387				multiply the matched entries, add the products. The <span class="qw-loud">lilac slice</span>
388				of each bar is its loud product, the <span class="qw-fast">mint slice</span> its fast
389				product; stacked, they are the score.
390			</span>
391		</div>
392	</div>
393	
394	<style>
395		.lab {
396			max-width: 860px;
397			margin: 2rem auto;
398			padding: 1.4rem 1.6rem 1.2rem;
399			background: var(--color-surface);
400			border: 1px solid color-mix(in oklab, var(--color-text) 8%, transparent);
401			border-radius: 14px;
402		}
403		.invite {
404			margin: 0 0 1rem;
405			font-size: 0.98rem;
406			line-height: 1.5;
407			color: color-mix(in oklab, var(--color-text) 88%, transparent);
408		}
409		.invite em { color: var(--color-brand-mint); font-style: normal; }
410		.invite .qw-loud, .lab .invite .qw-loud { color: var(--data-params); font-style: normal; }
411		.invite .qw-fast, .lab .invite .qw-fast { color: color-mix(in oklab, var(--color-brand-mint) 85%, var(--color-text)); font-style: normal; }
412		.mono { font-family: var(--font-mono); }
413	
414		.stage { display: flex; flex-direction: column; gap: 0.8rem; align-items: center; }
415		.arena-wrap { width: 100%; max-width: 620px; }
416		.arena { width: 100%; height: auto; touch-action: none; display: block; }
417	
418		.ring { fill: none; stroke: color-mix(in oklab, var(--color-text) 10%, transparent); stroke-width: 1; }
419		.tick { stroke: color-mix(in oklab, var(--color-text) 14%, transparent); stroke-width: 1; }
420		.axis { stroke: color-mix(in oklab, var(--color-text) 7%, transparent); stroke-width: 1; }
421	
422		.shaft { stroke-width: 2.4; stroke-linecap: round; }
423		.cand-stroke { stroke: var(--data-observed); }
424		.cand-fill { fill: var(--data-observed); }
425		.probe-stroke { stroke: var(--data-heat); }
426		.probe-fill { fill: var(--data-heat); }
427		.cand { opacity: 0.82; cursor: pointer; transition: opacity var(--motion-min-ms) var(--ease-out-quint); }
428		.cand.sel { opacity: 1; }
429		.cand.sel .shaft { stroke-width: 3; }
430	
431		.lab .arena text.lab { fill: var(--color-text); font-size: 13px; text-anchor: middle; dominant-baseline: middle; }
432		/* Decorative text must never swallow a pointer aimed at a handle. */
433		.arena text { pointer-events: none; }
434		.probe-lab { fill: var(--data-heat) !important; }
435		.angle { fill: color-mix(in oklab, var(--color-text) 45%, transparent); font-size: 12px; }
436	
437		.handle { fill: transparent; stroke: transparent; cursor: grab; }
438		.handle:focus-visible { outline: none; stroke: var(--color-brand-mint); stroke-width: 2; }
439		.handle.active { cursor: grabbing; }
440		.probe-handle { stroke: color-mix(in oklab, var(--data-heat) 55%, transparent); stroke-width: 1.5; stroke-dasharray: 3 3; }
